/**
 * Geolocation utilities for Next.js middleware and edge functions.
 *
 * Extracts geolocation data from common CDN/proxy headers
 * (Vercel, Cloudflare) and provides helpers for region checking
 * and distance calculation.
 */

export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

const COUNTRY_NAMES: Record<string, string> = {
  US: 'United States',
  GB: 'United Kingdom',
  DE: 'Germany',
  FR: 'France',
  JP: 'Japan',
  CN: 'China',
  IN: 'India',
  BR: 'Brazil',
  AU: 'Australia',
  CA: 'Canada',
}

function getHeaderValue(
  headers: Headers,
  name: string
): string | undefined {
  const value = headers.get(name)
  return value ?? undefined
}

export function geoFromHeaders(headers: Headers): Geo {
  const city = getHeaderValue(headers, 'x-vercel-ip-city')
  const countryCode =
    getHeaderValue(headers, 'x-vercel-ip-country') ??
    getHeaderValue(headers, 'cf-ipcountry')
  const region = getHeaderValue(headers, 'x-vercel-ip-country-region')
  const latitude = getHeaderValue(headers, 'x-vercel-ip-latitude')
  const longitude = getHeaderValue(headers, 'x-vercel-ip-longitude')
  const timezone = getHeaderValue(headers, 'x-vercel-ip-timezone')
  const country = countryCode
    ? COUNTRY_NAMES[countryCode.toUpperCase()]
    : undefined

  return {
    city,
    country,
    countryCode,
    region,
    latitude,
    longitude,
    timezone,
  }
}

export function geo({ headers }: { headers: Headers }): Geo {
  return geoFromHeaders(headers)
}

export function isInRegion(geo: Geo, regions: string[]): boolean {
  if (!geo.countryCode) {
    return false
  }
  const code = geo.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const R = 6371 // Earth's radius in kilometers
  const toRad = (deg: number) => (deg * Math.PI) / 180

  const lat1Num = parseFloat(lat1)
  const lon1Num = parseFloat(lon1)
  const lat2Num = parseFloat(lat2)
  const lon2Num = parseFloat(lon2)

  const dLat = toRad(lat2Num - lat1Num)
  const dLon = toRad(lon2Num - lon1Num)

  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(lat1Num)) *
      Math.cos(toRad(lat2Num)) *
      Math.sin(dLon / 2) *
      Math.sin(dLon / 2)

  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))

  return R * c
}

const geoExports = {
  geo: require('next/dist/server/web/spec-extension/geo').geo,
  geoFromHeaders:
    require('next/dist/server/web/spec-extension/geo').geoFromHeaders,
  isInRegion: require('next/dist/server/web/spec-extension/geo').isInRegion,
  geoDistance: require('next/dist/server/web/spec-extension/geo').geoDistance,
}

// https://nodejs.org/api/esm.html#commonjs-namespaces
// When importing CommonJS modules, the module.exports object is provided as the default export
module.exports = geoExports

// make import { xxx } from 'next/geo' work
exports.geo = geoExports.geo
exports.geoFromHeaders = geoExports.geoFromHeaders
exports.isInRegion = geoExports.isInRegion
exports.geoDistance = geoExports.geoDistance

